import { describe, expect, it } from 'vitest';
import {
  DEFAULT_BPSK,
  demodulateBpskFrame,
  modulateBpskFrame,
  type BpskOptions,
} from './bpsk-modem';
import { resolveFecProfile } from './fec-codec';
import { applyMarsChannel } from './mars-channel';
import { signalAmplitudeForEbN0 } from './link-budget';

const KEY = Uint8Array.from(
  'GNOSIS-RFKEY/1 prefixHash=66 prefixLen=7 boundaryDimension=12 stationCount=2 crc16=a4ce',
  (c) => c.charCodeAt(0),
);
const SPS = 300; // 2.4 MS/s / 8000 baud

function opts(fecName: string, amplitude: number): BpskOptions {
  return { ...DEFAULT_BPSK, fec: resolveFecProfile(fecName), amplitude };
}

describe('bpsk-modem', () => {
  it('clean round-trip recovers the exact cache key', () => {
    const o = opts('rs+conv', 0.6);
    const iq = modulateBpskFrame(KEY, o);
    const res = demodulateBpskFrame(iq, o);
    expect(res.ok).toBe(true);
    expect(res.payload).toEqual(KEY);
  });

  it('Mars-channel A/B: coherent BPSK + FEC recovers what raw cannot, at the same Eb/N0', () => {
    // 5.5 dB: the coherent-BPSK FEC cliff. rs+conv closes every seed; raw is destroyed.
    // (Coherent BPSK buys ~4 dB over the non-coherent MFSK PHY at a fixed BER, so this
    // cliff sits well below where uncoded recovery is possible.)
    const ebN0 = 5.5;
    const amp = signalAmplitudeForEbN0(ebN0, 'bpsk', SPS);
    const SEEDS = [11, 22, 33, 44, 55];

    let fecOk = 0;
    let rawOk = 0;
    for (const seed of SEEDS) {
      const fecIq = applyMarsChannel(modulateBpskFrame(KEY, opts('rs+conv', amp)), {
        noiseRms: 0.25,
        seed,
      }).iq;
      const fecRes = demodulateBpskFrame(fecIq, opts('rs+conv', amp), 0, 8 * SPS);
      if (fecRes.ok && fecRes.payload && Buffer.from(fecRes.payload).equals(Buffer.from(KEY))) {
        fecOk++;
      }

      const rawIq = applyMarsChannel(modulateBpskFrame(KEY, opts('none', amp)), {
        noiseRms: 0.25,
        seed,
      }).iq;
      const rawRes = demodulateBpskFrame(rawIq, opts('none', amp), 0, 8 * SPS);
      if (rawRes.ok && rawRes.payload && Buffer.from(rawRes.payload).equals(Buffer.from(KEY))) {
        rawOk++;
      }
    }
    // FEC closes the gap on every seed; raw is destroyed at this Eb/N0.
    expect(fecOk).toBe(SEEDS.length);
    expect(rawOk).toBe(0);
  });
});
